  ('police-f3743df6-moex-00460', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲因增建廚房，遭鄰居檢舉為違建，經主管機關查報認定後，以 A 函通知甲於 1 個月內自行拆 除。請問下列敘述何者正確？', '["甲未於1個月內自行拆除，主管機關應移送行政執行分署強制執行", "甲不服A函而提起行政救濟時，原處分即自動停止執行", "主管機關作成A函前，應給予其陳述意見之機會", "A函之法律性質為裁罰性不利處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00461', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲不服行政執行分署於行政執行程序中，限制出境之處分，向執行機關提出聲明異議而認無理由， 嗣後送行政執行署亦決定駁回時，其應如何救濟？', '["提起訴願", "向高等行政法院提起撤銷訴訟", "向高等行政法院提起課予義務訴訟", "向地方法院行政訴訟庭提起撤銷訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00462', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲因與傳染病確診者接觸，經主管機關下命居家隔離，甲不服處分經訴願駁回而向行政法院提起 行政訴訟時，居家隔離早已結束，請問其應提起何種訴訟類型？', '["撤銷訴訟", "課予義務訴訟", "確認行政處分違法訴訟", "一般給付訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00463', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '下列行政爭訟事件，何者行政法院未享有審判權？', '["某甲，臺北市政府公務員，因違法失職情節重大遭懲戒所生爭訟", "某乙，臺南市政府公務員，因執行職務違失遭主管長官根據公務人員考績法專案考績記兩大過 免職所生爭訟", "某丙，私立天主教輔仁大學學生，因考試作弊遭學校退學所生爭訟", "某丁，臺北市開業診所主持醫師，與中央健康保險署之間因全民健康保險醫事服務機構特約履 約問題所生爭訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00464', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲社會福利機構與主管機關締結行政契約，嗣後因甲社會福利機構人力不足無力再履約，主管機 關遂終止契約。請問下列敘述何者正確？', '["主管機關應對甲社會福利機構補償其財產上損失", "此係可歸責於甲社會福利機構，致有終止之事由，自應準用民法相關規定，而毋須補償其財產 上損失", "此為行政契約法上之情事變更原則，其成立當時之環境或基礎有所變動，發生超出合理範圍以 外之不可預測風險", "基於情事變更，因為主管機關未命甲社會福利機構繼續履行契約，故毋須補償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00465', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '代履行費用，義務人逾期未繳納者，主管機關得如何處理？', '["移送行政執行", "提起一般給付訴訟", "假處分", "提起民事訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00466', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '有關行政程序法第74條規定之寄存送達，下列敘述何者正確？', '["寄存送達只能由郵政機關為之", "寄存送達後，自第10日起生效", "寄存送達應製作1份送達通知書", "寄存機關自收受寄存文書之日起，應保存3個月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00467', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '因撤銷或變更原處分或決定之判決，而權利受損之第三人，如因非可歸責於己之事由，未參加訴 訟，致不能提出足以影響判決結果之攻擊或防禦方法者，得對於確定終局判決提起何種救濟？', '["再審", "重新審理", "確認訴訟", "第三人撤銷訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00468', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '下列何種機關所為之行為，在我國法制中有行政罰法之適用？', '["商品製造商所生產商品有損害消費者健康之虞，遭主管機關根據消費者保護法第 36 條規定， 命其下架且不得提供銷售", "駕駛人因違反道路交通管理處罰條例之規定，遭吊銷駕駛執照", "納稅義務人申報年度綜合所得稅，所申報之醫療費用因未提供單據，遭稅捐稽徵機關剔除", "違章建築所有權人，因未依限期拆除違章建築，遭建築法主管機關根據該法強制拆除"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00469', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '臺北市民王大毛，向臺北市政府申請設置加油站，經臺北市政府許可，發給許可文書。但在該許 可文書中，誤將申請人「王大毛」繕寫為「王太毛」。假設相關卷宗資料中並無「王太毛」其人， 根據行政程序法之規定，該許可文書：', '["構成無效之行政處分，自始當然確定不生效力", "機關不得依職權更正該誤寫之瑕疵", "機關得依申請更正之", "僅得向行政法院起訴請求發給特定內容之許可文書"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL)
